import { describe, it, expect, beforeEach } from 'vitest';
import {
  propagateUncertainty,
  calculateBands,
  analyticRatioBands,
  monteCarloVaRBands,
  type UncertaintyInput,
  type UncertaintyBands,
} from '../uncertainty';

describe('Uncertainty Propagation Module', () => {
  // ===== BASIC UNCERTAINTY PROPAGATION =====
  describe('propagateUncertainty - basic propagation', () => {
    it('should propagate zero variance to zero band width', () => {
      const input: UncertaintyInput = {
        value: 100,
        stddev: 0,
        percentile: [0.1, 0.9],
      };
      const result = propagateUncertainty(input);

      expect(result.value).toBe(100);
      expect(result.p10).toBe(100);
      expect(result.p90).toBe(100);
      expect(result.bandWidth).toBe(0);
    });

    it('should widen bands with increasing variance', () => {
      const input1: UncertaintyInput = {
        value: 100,
        stddev: 5,
        percentile: [0.1, 0.9],
      };
      const input2: UncertaintyInput = {
        value: 100,
        stddev: 10,
        percentile: [0.1, 0.9],
      };

      const result1 = propagateUncertainty(input1);
      const result2 = propagateUncertainty(input2);

      expect(result2.bandWidth).toBeGreaterThan(result1.bandWidth);
      expect(result2.p90 - result2.p10).toBeGreaterThan(result1.p90 - result1.p10);
    });

    it('should handle positive values with uncertainty', () => {
      const input: UncertaintyInput = {
        value: 1000,
        stddev: 100,
        percentile: [0.1, 0.9],
      };
      const result = propagateUncertainty(input);

      expect(result.value).toBe(1000);
      expect(result.p10).toBeLessThan(1000);
      expect(result.p90).toBeGreaterThan(1000);
      expect(result.p10).toBeGreaterThan(0);
    });

    it('should return bands centered around value for symmetric distributions', () => {
      const input: UncertaintyInput = {
        value: 500,
        stddev: 50,
        percentile: [0.1, 0.9],
      };
      const result = propagateUncertainty(input);

      const lowerDist = result.value - result.p10;
      const upperDist = result.p90 - result.value;
      expect(Math.abs(lowerDist - upperDist)).toBeLessThan(lowerDist * 0.01);
    });
  });

  // ===== BAND CALCULATION TESTS =====
  describe('calculateBands - uncertainty band computation', () => {
    it('should generate required band properties', () => {
      const bands = calculateBands(100, 10, [0.1, 0.9]);

      expect(bands).toHaveProperty('value');
      expect(bands).toHaveProperty('p10');
      expect(bands).toHaveProperty('p90');
      expect(bands).toHaveProperty('bandWidth');
      expect(bands).toHaveProperty('confidenceLevel');
    });

    it('should collapse bands to point value at zero variance', () => {
      const bands = calculateBands(250, 0, [0.1, 0.9]);

      expect(bands.value).toBe(250);
      expect(bands.p10).toBe(250);
      expect(bands.p90).toBe(250);
      expect(bands.bandWidth).toBe(0);
    });

    it('should maintain p10 < value < p90 invariant', () => {
      const bands = calculateBands(100, 20, [0.1, 0.9]);

      expect(bands.p10).toBeLessThan(bands.value);
      expect(bands.value).toBeLessThan(bands.p90);
      expect(bands.p10).toBeLessThan(bands.p90);
    });

    it('should scale band width with stddev linearly (approximately)', () => {
      const bands1 = calculateBands(100, 5, [0.1, 0.9]);
      const bands2 = calculateBands(100, 10, [0.1, 0.9]);

      expect(bands2.bandWidth).toBeGreaterThan(bands1.bandWidth);
      const ratio = bands2.bandWidth / bands1.bandWidth;
      expect(ratio).toBeGreaterThan(1.5);
      expect(ratio).toBeLessThan(3);
    });

    it('should handle small positive stddev values', () => {
      const bands = calculateBands(100, 0.1, [0.1, 0.9]);

      expect(bands.p10).toBeCloseTo(100, 1);
      expect(bands.p90).toBeCloseTo(100, 1);
      expect(bands.bandWidth).toBeGreaterThan(0);
      expect(bands.bandWidth).toBeLessThan(1);
    });

    it('should respect custom percentile bounds', () => {
      const bands1 = calculateBands(100, 10, [0.05, 0.95]);
      const bands2 = calculateBands(100, 10, [0.25, 0.75]);

      expect(bands1.bandWidth).toBeGreaterThan(bands2.bandWidth);
      expect(bands1.p10).toBeLessThan(bands2.p10);
      expect(bands1.p90).toBeGreaterThan(bands2.p90);
    });
  });

  // ===== ANALYTIC RATIO BANDS =====
  describe('analyticRatioBands - analytic ratio calculation', () => {
    it('should compute ratio with zero uncertainty', () => {
      const result = analyticRatioBands(
        { value: 100, stddev: 0 },
        { value: 10, stddev: 0 },
        [0.1, 0.9]
      );

      expect(result.value).toBeCloseTo(10, 2);
      expect(result.p10).toBeCloseTo(10, 2);
      expect(result.p90).toBeCloseTo(10, 2);
    });

    it('should widen bands when numerator uncertainty increases', () => {
      const base: UncertaintyInput = { value: 10, stddev: 0 };
      const denom1: UncertaintyInput = { value: 100, stddev: 5 };
      const denom2: UncertaintyInput = { value: 100, stddev: 20 };

      const result1 = analyticRatioBands(denom1, base, [0.1, 0.9]);
      const result2 = analyticRatioBands(denom2, base, [0.1, 0.9]);

      expect(result2.bandWidth).toBeGreaterThan(result1.bandWidth);
    });

    it('should widen bands when denominator uncertainty increases', () => {
      const numerator: UncertaintyInput = { value: 100, stddev: 0 };
      const denom1: UncertaintyInput = { value: 10, stddev: 1 };
      const denom2: UncertaintyInput = { value: 10, stddev: 5 };

      const result1 = analyticRatioBands(numerator, denom1, [0.1, 0.9]);
      const result2 = analyticRatioBands(numerator, denom2, [0.1, 0.9]);

      expect(result2.bandWidth).toBeGreaterThan(result1.bandWidth);
    });

    it('should handle very small denominator values safely', () => {
      const result = analyticRatioBands(
        { value: 100, stddev: 10 },
        { value: 0.01, stddev: 0.001 },
        [0.1, 0.9]
      );

      expect(Number.isFinite(result.value)).toBe(true);
      expect(Number.isFinite(result.p10)).toBe(true);
      expect(Number.isFinite(result.p90)).toBe(true);
      expect(result.value).toBeGreaterThan(0);
    });

    it('should compute ratio correctly for standard case', () => {
      const result = analyticRatioBands(
        { value: 200, stddev: 20 },
        { value: 50, stddev: 5 },
        [0.1, 0.9]
      );

      expect(result.value).toBeCloseTo(4, 1);
      expect(result.p10).toBeLessThan(4);
      expect(result.p90).toBeGreaterThan(4);
    });

    it('should mark analytic calculation method in result', () => {
      const result = analyticRatioBands(
        { value: 100, stddev: 10 },
        { value: 10, stddev: 1 },
        [0.1, 0.9]
      );

      expect(result.method).toBe('analytic');
    });
  });

  // ===== MONTE CARLO VAR/SCR BANDS =====
  describe('monteCarloVaRBands - Monte Carlo VaR/SCR calculation', () => {
    it('should converge to point value at zero variance with fixed seed', () => {
      const result = monteCarloVaRBands(
        { value: 100, stddev: 0 },
        { seed: 12345, iterations: 10000 },
        [0.1, 0.9]
      );

      expect(result.p10).toBeCloseTo(100, 0);
      expect(result.p90).toBeCloseTo(100, 0);
      expect(result.bandWidth).toBeLessThan(1);
    });

    it('should widen bands with increasing variance', () => {
      const result1 = monteCarloVaRBands(
        { value: 100, stddev: 5 },
        { seed: 12345, iterations: 10000 },
        [0.1, 0.9]
      );
      const result2 = monteCarloVaRBands(
        { value: 100, stddev: 20 },
        { seed: 12345, iterations: 10000 },
        [0.1, 0.9]
      );

      expect(result2.bandWidth).toBeGreaterThan(result1.bandWidth);
    });

    it('should be reproducible with same seed', () => {
      const result1 = monteCarloVaRBands(
        { value: 100, stddev: 15 },
        { seed: 42, iterations: 5000 },
        [0.1, 0.9]
      );
      const result2 = monteCarloVaRBands(
        { value: 100, stddev: 15 },
        { seed: 42, iterations: 5000 },
        [0.1, 0.9]
      );

      expect(result1.value).toBe(result2.value);
      expect(result1.p10).toBe(result2.p10);
      expect(result1.p90).toBe(result2.p90);
    });

    it('should produce different results with different seeds', () => {
      const result1 = monteCarloVaRBands(
        { value: 100, stddev: 15 },
        { seed: 1, iterations: 5000 },
        [0.1, 0.9]
      );
      const result2 = monteCarloVaRBands(
        { value: 100, stddev: 15 },
        { seed: 999, iterations: 5000 },
        [0.1, 0.9]
      );

      expect(Math.abs(result1.p10 - result2.p10)).toBeGreaterThan(0.1);
    });

    it('should maintain p10 < value < p90 invariant', () => {
      const result = monteCarloVaRBands(
        { value: 500, stddev: 50 },
        { seed: 12345, iterations: 10000 },
        [0.1, 0.9]
      );

      expect(result.p10).toBeLessThanOrEqual(result.value);
      expect(result.value).toBeLessThanOrEqual(result.p90);
    });

    it('should use specified iteration count for convergence', () => {
      const result = monteCarloVaRBands(
        { value: 100, stddev: 10 },
        { seed: 12345, iterations: 50000 },
        [0.1, 0.9]
      );

      expect(result.iterations).toBe(50000);
      expect(result.method).toBe('monte-carlo');
    });

    it('should handle large value magnitudes', () => {
      const result = monteCarloVaRBands(
        { value: 1000000, stddev: 50000 },
        { seed: 12345, iterations: 10000 },
        [0.1, 0.9]
      );

      expect(Number.isFinite(result.value)).toBe(true);
      expect(Number.isFinite(result.p10)).toBe(true);
      expect(Number.isFinite(result.p90)).toBe(true);
      expect(result.p10).toBeGreaterThan(0);
    });
  });

  // ===== EDGE CASES AND BOUNDARY CONDITIONS =====
  describe('Edge Cases - boundary conditions', () => {
    it('should handle very small positive values', () => {
      const result = propagateUncertainty({
        value: 0.001,
        stddev: 0.0001,
        percentile: [0.1, 0.9],
      });

      expect(result.value).toBe(0.001);
      expect(result.p10).toBeGreaterThan(0);
      expect(result.p90).toBeGreaterThan(result.p10);
    });

    it('should handle large value magnitudes', () => {
      const result = propagateUncertainty({
        value: 1e9,
        stddev: 1e7,
        percentile: [0.1, 0.9],
      });

      expect(Number.isFinite(result.value)).toBe(true);
      expect(Number.isFinite(result.p10)).toBe(true);
      expect(Number.isFinite(result.p90)).toBe(true);
    });

    it('should reject negative values', () => {
      expect(() => {
        propagateUncertainty({
          value: -100,
          stddev: 10,
          percentile: [0.1, 0.9],
        });
      }).toThrow();
    });

    it('should reject negative stddev', () => {
      expect(() => {
        propagateUncertainty({
          value: 100,
          stddev: -10,
          percentile: [0.1, 0.9],
        });
      }).toThrow();
    });

    it('should reject invalid percentile order', () => {
      expect(() => {
        propagateUncertainty({
          value: 100,
          stddev: 10,
          percentile: [0.9, 0.1],
        });
      }).toThrow();
    });

    it('should reject percentiles outside [0, 1]', () => {
      expect(() => {
        propagateUncertainty({
          value: 100,
          stddev: 10,
          percentile: [-0.1, 0.9],
        });
      }).toThrow();

      expect(() => {
        propagateUncertainty({
          value: 100,
          stddev: 10,
          percentile: [0.1, 1.1],
        });
      }).toThrow();
    });
  });

  // ===== METRIC CALCULATOR INTEGRATION =====
  describe('Integration with metric calculators', () => {
    it('should not modify curator output shape', () => {
      const input: UncertaintyInput = {
        value: 100,
        stddev: 10,
        percentile: [0.1, 0.9],
      };
      const result = propagateUncertainty(input);

      expect(result).toHaveProperty('value');
      expect(result).toHaveProperty('p10');
      expect(result).toHaveProperty('p90');
      expect(result).toHaveProperty('bandWidth');
      expect(result).toHaveProperty('confidenceLevel');
      expect(Object.keys(result).length).toBeLessThanOrEqual(6);
    });

    it('should expose helper for separate curator integration', () => {
      const bands: UncertaintyBands = {
        value: 100,
        p10: 85,
        p90: 115,
        bandWidth: 30,
        confidenceLevel: 0.8,
        method: 'analytic',
      };

      expect(bands.value).toBe(100);
      expect(typeof bands.bandWidth).toBe('number');
    });
  });

  // ===== DETERMINISM AND REPRODUCIBILITY =====
  describe('Determinism - reproducible results', () => {
    it('should produce identical results for same input (no Date.now)', () => {
      const input: UncertaintyInput = {
        value: 250,
        stddev: 25,
        percentile: [0.1, 0.9],
      };

      const result1 = propagateUncertainty(input);
      const result2 = propagateUncertainty(input);

      expect(result1.value).toBe(result2.value);
      expect(result1.p10).toBe(result2.p10);
      expect(result1.p90).toBe(result2.p90);
    });

    it('should support seeded randomization for Monte Carlo', () => {
      const options1 = { seed: 123, iterations: 5000 };
      const options2 = { seed: 123, iterations: 5000 };
      const options3 = { seed: 456, iterations: 5000 };

      const input: UncertaintyInput = {
        value: 100,
        stddev: 15,
      };

      const result1 = monteCarloVaRBands(input, options1, [0.1, 0.9]);
      const result2 = monteCarloVaRBands(input, options2, [0.1, 0.9]);
      const result3 = monteCarloVaRBands(input, options3, [0.1, 0.9]);

      expect(result1.p10).toBe(result2.p10);
      expect(result1.p90).toBe(result2.p90);
      expect(Math.abs(result1.p10 - result3.p10)).toBeGreaterThan(0.1);
    });
  });

  // ===== BAND WIDTH PROPERTIES =====
  describe('bandWidth - uncertainty quantification', () => {
    it('should define bandWidth as p90 - p10', () => {
      const result = propagateUncertainty({
        value: 100,
        stddev: 20,
        percentile: [0.1, 0.9],
      });

      expect(result.bandWidth).toBeCloseTo(result.p90 - result.p10, 5);
    });

    it('should increase monotonically with stddev', () => {
      const bandWidths: number[] = [];
      for (let stddev = 1; stddev <= 50; stddev += 5) {
        const result = propagateUncertainty({
          value: 100,
          stddev,
          percentile: [0.1, 0.9],
        });
        bandWidths.push(result.bandWidth);
      }

      for (let i = 1; i < bandWidths.length; i++) {
        expect(bandWidths[i]).toBeGreaterThanOrEqual(bandWidths[i - 1]);
      }
    });

    it('should scale approximately linearly with stddev for normal distribution', () => {
      const result1 = propagateUncertainty({
        value: 100,
        stddev: 10,
        percentile: [0.1, 0.9],
      });
      const result2 = propagateUncertainty({
        value: 100,
        stddev: 20,
        percentile: [0.1, 0.9],
      });

      const ratio = result2.bandWidth / result1.bandWidth;
      expect(ratio).toBeCloseTo(2, 0.5);
    });
  });

  // ===== CONFIDENCE LEVEL =====
  describe('confidenceLevel - uncertainty coverage', () => {
    it('should correctly calculate confidence from percentiles', () => {
      const result = propagateUncertainty({
        value: 100,
        stddev: 10,
        percentile: [0.1, 0.9],
      });

      expect(result.confidenceLevel).toBeCloseTo(0.8, 1);
    });

    it('should vary with different percentile bounds', () => {
      const result1 = propagateUncertainty({
        value: 100,
        stddev: 10,
        percentile: [0.1, 0.9],
      });
      const result2 = propagateUncertainty({
        value: 100,
        stddev: 10,
        percentile: [0.05, 0.95],
      });

      expect(result2.confidenceLevel).toBeGreaterThan(result1.confidenceLevel);
    });
  });

  // ===== MULTIPLE METRIC COMPOSITION =====
  describe('Composition - multiple metrics with uncertainty', () => {
    it('should allow composing multiple uncertain metrics', () => {
      const metric1 = propagateUncertainty({
        value: 100,
        stddev: 10,
        percentile: [0.1, 0.9],
      });
      const metric2 = propagateUncertainty({
        value: 50,
        stddev: 5,
        percentile: [0.1, 0.9],
      });

      expect(metric1.value + metric2.value).toBeCloseTo(150, 0);
      const composedBandWidth = (metric1.p90 + metric2.p90) - (metric1.p10 + metric2.p10);
      expect(composedBandWidth).toBeGreaterThan(metric1.bandWidth + metric2.bandWidth * 0.9);
    });
  });
});
